/**
 * Priority-based notification routing.
 *
 * Maps notification priority levels to delivery channels:
 * - urgent → sms (immediate attention)
 * - normal → email (standard delivery)
 * - low → webhook (background/batch delivery)
 */

export type NotificationPriority = 'urgent' | 'normal' | 'low';

const DEFAULT_ROUTING: Record<NotificationPriority, string> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export class PriorityRouterService {
  private routing: Record<NotificationPriority, string>;

  constructor(routing?: Partial<Record<NotificationPriority, string>>) {
    this.routing = { ...DEFAULT_ROUTING, ...routing };
  }

  /**
   * Resolve the delivery channel for a given priority level.
   */
  resolve(priority: NotificationPriority): string {
    return this.routing[priority];
  }

  /**
   * Get the full routing table.
   */
  getRouting(): Record<NotificationPriority, string> {
    return { ...this.routing };
  }
}

/**
 * Audit logging service for notification dispatch.
 *
 * Records every notification dispatched through the system by subscribing
 * to notification:requested events on the EventBus. Provides query methods
 * for retrieving audit entries.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent } from '../events/event-types.js';

export interface AuditEntry {
  id: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  timestamp: Date;
  recordedAt: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      this.record(event);
    });
  }

  /**
   * Record a notification event as an audit entry.
   */
  private record(event: NotificationRequestedEvent): void {
    const entry: AuditEntry = {
      id: generateAuditId(),
      channel: event.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      timestamp: event.timestamp,
      recordedAt: new Date(),
    };
    this.entries.push(entry);
  }

  /**
   * Get all audit entries.
   */
  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  /**
   * Get audit entries for a specific channel.
   */
  getEntriesByChannel(channel: string): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  /**
   * Get audit entries for a specific recipient.
   */
  getEntriesByRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  /**
   * Get the total number of audit entries.
   */
  getEntryCount(): number {
    return this.entries.length;
  }

  /**
   * Clear all audit entries (useful for testing).
   */
  clearEntries(): void {
    this.entries = [];
  }
}

/**
 * Per-user notification preferences.
 *
 * Allows users to override the default priority-based channel routing.
 * When a user has a channel preference set, it takes precedence over
 * the priority router's default channel selection.
 */

export interface UserPreferences {
  /** Override channel for all notifications, regardless of priority. */
  preferredChannel?: string;
  /** Per-priority channel overrides. Takes precedence over preferredChannel. */
  channelByPriority?: Partial<Record<string, string>>;
}

export class NotificationPreferencesService {
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Set preferences for a user.
   */
  setPreferences(userId: string, prefs: UserPreferences): void {
    this.preferences.set(userId, prefs);
  }

  /**
   * Get preferences for a user, or undefined if none set.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Resolve the channel for a user given a priority.
   * Returns the user's preferred channel if set, or undefined to fall back
   * to the priority router's default.
   */
  resolveChannel(userId: string, priority: string): string | undefined {
    const prefs = this.preferences.get(userId);
    if (!prefs) return undefined;

    // Per-priority override takes highest precedence
    const byPriority = prefs.channelByPriority?.[priority];
    if (byPriority) return byPriority;

    // Global preferred channel
    return prefs.preferredChannel;
  }

  /**
   * Remove preferences for a user.
   */
  removePreferences(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Clear all preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

