/**
 * Resolve the delivery channel for a notification.
 *
 * Resolution order:
 * 1. Explicit channel parameter (highest priority)
 * 2. User preference (from NotificationPreferencesService)
 * 3. Priority-based routing (from PriorityRouterService)
 * 4. Default: 'email'
 */
private resolveChannel(params: {
  recipient: string;
  channel?: string;
  priority?: NotificationPriority;
}): string {
  if (params.channel) return params.channel;

  const priority = params.priority ?? 'normal';

  if (this.preferencesService) {
    const preferred = this.preferencesService.resolveChannel(params.recipient, priority);
    if (preferred) return preferred;
  }

  return this.priorityRouter.resolve(priority);
}

/**
 * Send a notification. Stores locally and dispatches via EventBus
 * so channel handlers (email, SMS, etc.) can deliver it.
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  channel?: string;
  priority?: NotificationPriority;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

  // Resolve channel via priority routing and user preferences
  const channel = this.resolveChannel(params);
  this.eventBus.emit<NotificationRequestedEvent>({
    type: 'notification:requested',
    channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
