import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailChannelHandler,
  SmsChannelHandler,
  WebhookChannelHandler,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PriorityRouterService } from '../../src/services/priority-router.service.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('Notification Integration: priority routing → channel selection → audit', () => {
  let eventBus: EventBus;
  let priorityRouter: PriorityRouterService;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;
  let notificationService: NotificationService;
  let emailHandler: EmailChannelHandler;
  let smsHandler: SmsChannelHandler;
  let webhookHandler: WebhookChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    priorityRouter = new PriorityRouterService();
    auditService = new AuditService(eventBus);
    preferencesService = new NotificationPreferencesService();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetAuditIdCounter();

    // Wire up all channel handlers
    emailHandler = new EmailChannelHandler(eventBus);
    smsHandler = new SmsChannelHandler(eventBus);
    webhookHandler = new WebhookChannelHandler(eventBus);

    notificationService = new NotificationService(eventBus, {
      priorityRouter,
      preferencesService,
    });
  });

  describe('priority-based routing', () => {
    it('should route urgent notifications to SMS', () => {
      notificationService.dispatchNotification({
        recipient: '+1234567890',
        subject: 'Server Down',
        body: 'Production server is unresponsive',
        priority: 'urgent',
      });

      expect(smsHandler.getDeliveredCount()).toBe(1);
      expect(emailHandler.getDeliveredCount()).toBe(0);
      expect(webhookHandler.getDeliveredCount()).toBe(0);

      const delivered = smsHandler.getDeliveredMessages();
      expect(delivered[0]?.subject).toBe('Server Down');
    });

    it('should route normal notifications to email', () => {
      notificationService.dispatchNotification({
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed',
        priority: 'normal',
      });

      expect(emailHandler.getDeliveredCount()).toBe(1);
      expect(smsHandler.getDeliveredCount()).toBe(0);
      expect(webhookHandler.getDeliveredCount()).toBe(0);

      const delivered = emailHandler.getDeliveredEmails();
      expect(delivered[0]?.subject).toBe('Order Confirmation');
    });

    it('should route low-priority notifications to webhook', () => {
      notificationService.dispatchNotification({
        recipient: 'https://hooks.example.com/updates',
        subject: 'Weekly Digest',
        body: 'Here is your weekly summary',
        priority: 'low',
      });

      expect(webhookHandler.getDeliveredCount()).toBe(1);
      expect(emailHandler.getDeliveredCount()).toBe(0);
      expect(smsHandler.getDeliveredCount()).toBe(0);

      const delivered = webhookHandler.getDeliveredPayloads();
      expect(delivered[0]?.subject).toBe('Weekly Digest');
    });

    it('should default to normal priority (email) when no priority specified', () => {
      notificationService.dispatchNotification({
        recipient: 'bob@example.com',
        subject: 'Default Priority',
        body: 'No priority specified',
      });

      expect(emailHandler.getDeliveredCount()).toBe(1);
      expect(smsHandler.getDeliveredCount()).toBe(0);
      expect(webhookHandler.getDeliveredCount()).toBe(0);
    });
  });

  describe('audit logging', () => {
    it('should record an audit entry for every dispatched notification', () => {
      notificationService.dispatchNotification({
        recipient: 'alice@example.com',
        subject: 'Test Notification',
        body: 'Audit test',
        priority: 'normal',
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.subject).toBe('Test Notification');
      expect(entries[0]?.id).toBe('audit-0001');
    });

    it('should record audit entries for all priority levels', () => {
      notificationService.dispatchNotification({
        recipient: '+1234567890',
        subject: 'Urgent',
        body: 'Urgent body',
        priority: 'urgent',
      });
      notificationService.dispatchNotification({
        recipient: 'user@example.com',
        subject: 'Normal',
        body: 'Normal body',
        priority: 'normal',
      });
      notificationService.dispatchNotification({
        recipient: 'https://hooks.example.com',
        subject: 'Low',
        body: 'Low body',
        priority: 'low',
      });

      expect(auditService.getEntryCount()).toBe(3);
      expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('webhook')).toHaveLength(1);
    });

    it('should record the correct channel even when user preferences override routing', () => {
      preferencesService.setPreferences('alice@example.com', {
        preferredChannel: 'sms',
      });

      notificationService.dispatchNotification({
        recipient: 'alice@example.com',
        subject: 'Preference Override',
        body: 'Should be SMS per preference',
        priority: 'low', // would normally go to webhook
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
    });
  });

  describe('user preferences override priority routing', () => {
    it('should use user preferred channel instead of priority default', () => {
      preferencesService.setPreferences('bob@example.com', {
        preferredChannel: 'webhook',
      });

      notificationService.dispatchNotification({
        recipient: 'bob@example.com',
        subject: 'Override Test',
        body: 'Should go to webhook despite urgent priority',
        priority: 'urgent', // would normally go to SMS
      });

      expect(webhookHandler.getDeliveredCount()).toBe(1);
      expect(smsHandler.getDeliveredCount()).toBe(0);
    });

    it('should use per-priority channel override over global preference', () => {
      preferencesService.setPreferences('carol@example.com', {
        preferredChannel: 'webhook', // global fallback
        channelByPriority: {
          urgent: 'email', // override specifically for urgent
        },
      });

      // Urgent → should use per-priority override (email), not global (webhook)
      notificationService.dispatchNotification({
        recipient: 'carol@example.com',
        subject: 'Urgent Override',
        body: 'Per-priority override',
        priority: 'urgent',
      });

      expect(emailHandler.getDeliveredCount()).toBe(1);
      expect(webhookHandler.getDeliveredCount()).toBe(0);

      // Normal → should use global preference (webhook), not default (email)
      notificationService.dispatchNotification({
        recipient: 'carol@example.com',
        subject: 'Normal Fallback',
        body: 'Global preference fallback',
        priority: 'normal',
      });

      expect(webhookHandler.getDeliveredCount()).toBe(1);
    });

    it('should fall back to priority routing when user has no preferences', () => {
      // No preferences set for dave
      notificationService.dispatchNotification({
        recipient: 'dave@example.com',
        subject: 'No Preference',
        body: 'Should use default priority routing',
        priority: 'urgent',
      });

      expect(smsHandler.getDeliveredCount()).toBe(1);
    });

    it('should use explicit channel parameter over both preferences and priority', () => {
      preferencesService.setPreferences('eve@example.com', {
        preferredChannel: 'webhook',
      });

      notificationService.dispatchNotification({
        recipient: 'eve@example.com',
        subject: 'Explicit Channel',
        body: 'Should use explicitly specified channel',
        priority: 'urgent',
        channel: 'email', // explicit override trumps everything
      });

      expect(emailHandler.getDeliveredCount()).toBe(1);
      expect(smsHandler.getDeliveredCount()).toBe(0);
      expect(webhookHandler.getDeliveredCount()).toBe(0);
    });
  });

  describe('full end-to-end flow', () => {
    it('should dispatch, route by priority, deliver to correct channel, and audit log', () => {
      notificationService.dispatchNotification({
        recipient: 'alice@example.com',
        subject: 'E2E Urgent',
        body: 'Full flow test',
        priority: 'urgent',
      });

      // 1. Notification was stored
      expect(notificationService.getNotificationCount()).toBe(1);

      // 2. Routed to SMS (urgent)
      expect(smsHandler.getDeliveredCount()).toBe(1);
      expect(smsHandler.getDeliveredMessages()[0]?.recipient).toBe('alice@example.com');

      // 3. Audit entry recorded
      expect(auditService.getEntryCount()).toBe(1);
      const audit = auditService.getEntries()[0]!;
      expect(audit.channel).toBe('sms');
      expect(audit.recipient).toBe('alice@example.com');
      expect(audit.subject).toBe('E2E Urgent');
    });

    it('should handle multiple notifications with mixed priorities and preferences', () => {
      preferencesService.setPreferences('vip@example.com', {
        preferredChannel: 'email', // VIP always wants email
      });

      // Urgent to regular user → SMS
      notificationService.dispatchNotification({
        recipient: 'regular@example.com',
        subject: 'Alert',
        body: 'Urgent alert',
        priority: 'urgent',
      });

      // Urgent to VIP user → email (preference override)
      notificationService.dispatchNotification({
        recipient: 'vip@example.com',
        subject: 'VIP Alert',
        body: 'Urgent but VIP prefers email',
        priority: 'urgent',
      });

      // Low priority → webhook
      notificationService.dispatchNotification({
        recipient: 'system@example.com',
        subject: 'Log Entry',
        body: 'Low priority log',
        priority: 'low',
      });

      // Verify channel deliveries
      expect(smsHandler.getDeliveredCount()).toBe(1);
      expect(emailHandler.getDeliveredCount()).toBe(1);
      expect(webhookHandler.getDeliveredCount()).toBe(1);

      // Verify audit has all 3
      expect(auditService.getEntryCount()).toBe(3);
      const channels = auditService.getEntries().map((e) => e.channel);
      expect(channels).toEqual(['sms', 'email', 'webhook']);

      // Verify notifications stored
      expect(notificationService.getNotificationCount()).toBe(3);
    });
  });
});

describe('PriorityRouterService', () => {
  it('should map urgent to sms', () => {
    const router = new PriorityRouterService();
    expect(router.resolve('urgent')).toBe('sms');
  });

  it('should map normal to email', () => {
    const router = new PriorityRouterService();
    expect(router.resolve('normal')).toBe('email');
  });

  it('should map low to webhook', () => {
    const router = new PriorityRouterService();
    expect(router.resolve('low')).toBe('webhook');
  });

  it('should support custom routing overrides', () => {
    const router = new PriorityRouterService({ urgent: 'email' });
    expect(router.resolve('urgent')).toBe('email');
    expect(router.resolve('normal')).toBe('email'); // unchanged
  });
});

describe('AuditService', () => {
  let eventBus: EventBus;
  let auditService: AuditService;

  beforeEach(() => {
    eventBus = new EventBus();
    resetAuditIdCounter();
    auditService = new AuditService(eventBus);
  });

  it('should record audit entries from notification:requested events', async () => {
    await eventBus.emit({
      type: 'notification:requested' as const,
      channel: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test body',
      timestamp: new Date(),
    });

    expect(auditService.getEntryCount()).toBe(1);
    expect(auditService.getEntries()[0]?.id).toBe('audit-0001');
  });

  it('should filter entries by channel', async () => {
    await eventBus.emit({
      type: 'notification:requested' as const,
      channel: 'sms',
      recipient: '+123',
      subject: 'SMS',
      body: 'SMS body',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested' as const,
      channel: 'email',
      recipient: 'a@b.com',
      subject: 'Email',
      body: 'Email body',
      timestamp: new Date(),
    });

    expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('webhook')).toHaveLength(0);
  });

  it('should filter entries by recipient', async () => {
    await eventBus.emit({
      type: 'notification:requested' as const,
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'For Alice',
      body: 'body',
      timestamp: new Date(),
    });

    expect(auditService.getEntriesByRecipient('alice@example.com')).toHaveLength(1);
    expect(auditService.getEntriesByRecipient('bob@example.com')).toHaveLength(0);
  });
});

describe('NotificationPreferencesService', () => {
  let preferencesService: NotificationPreferencesService;

  beforeEach(() => {
    preferencesService = new NotificationPreferencesService();
  });

  it('should return undefined when no preferences set', () => {
    expect(preferencesService.resolveChannel('unknown-user', 'normal')).toBeUndefined();
  });

  it('should return preferred channel when set', () => {
    preferencesService.setPreferences('user-1', { preferredChannel: 'sms' });
    expect(preferencesService.resolveChannel('user-1', 'normal')).toBe('sms');
  });

  it('should prioritize per-priority override over global preference', () => {
    preferencesService.setPreferences('user-1', {
      preferredChannel: 'webhook',
      channelByPriority: { urgent: 'email' },
    });
    expect(preferencesService.resolveChannel('user-1', 'urgent')).toBe('email');
    expect(preferencesService.resolveChannel('user-1', 'normal')).toBe('webhook');
  });

  it('should remove preferences', () => {
    preferencesService.setPreferences('user-1', { preferredChannel: 'sms' });
    preferencesService.removePreferences('user-1');
    expect(preferencesService.resolveChannel('user-1', 'normal')).toBeUndefined();
  });
});

