+/**
+ * Audit logging service for notification dispatch.
+ *
+ * Records every notification dispatched through the system by subscribing
+ * to notification:requested events on the EventBus. Provides query methods
+ * for retrieving audit entries.
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationRequestedEvent } from '../events/event-types.js';
+
+export interface AuditEntry {
+  id: string;
+  channel: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  timestamp: Date;
+  recordedAt: Date;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private entries: AuditEntry[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
+      this.record(event);
+    });
+  }
+
+  /**
+   * Record a notification event as an audit entry.
+   */
+  private record(event: NotificationRequestedEvent): void {
+    const entry: AuditEntry = {
+      id: generateAuditId(),
+      channel: event.channel,
+      recipient: event.recipient,
+      subject: event.subject,
+      body: event.body,
+      timestamp: event.timestamp,
+      recordedAt: new Date(),
+    };
+    this.entries.push(entry);
+  }
+
+  /**
+   * Get all audit entries.
+   */
+  getEntries(): AuditEntry[] {
+    return [...this.entries];
+  }
+
+  /**
+   * Get audit entries for a specific channel.
+   */
+  getEntriesByChannel(channel: string): AuditEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  /**
+   * Get audit entries for a specific recipient.
+   */
+  getEntriesByRecipient(recipient: string): AuditEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  /**
+   * Get the total number of audit entries.
+   */
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  /**
+   * Clear all audit entries (useful for testing).
+   */
+  clearEntries(): void {
+    this.entries = [];
+  }
+}

